# 1) start websockify (persistent) bridging noVNC web + ws proxy to VNC 5901
pkill -f 'websockify' 2>/dev/null; sleep 1
websockify -D --web /usr/share/novnc 6080 localhost:5901
sleep 2
ss -ltn | grep 6080 && echo "websockify up"

# 2) nginx site on port 80 -> proxy to websockify (handles static + ws upgrade)
cat >/etc/nginx/sites-available/novnc <<'EOF'
server {
    listen 80 default_server;
    listen [::]:80 default_server;
    server_name _;

    location = / { return 302 /vnc.html; }

    location / {
        proxy_pass http://127.0.0.1:6080;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_read_timeout 3600s;
        proxy_send_timeout 3600s;
    }
}
EOF
rm -f /etc/nginx/sites-enabled/default
ln -sf /etc/nginx/sites-available/novnc /etc/nginx/sites-enabled/novnc
nginx -t 2>&1

